function solve(nums) {
    const n = nums.length;
    if (n === 0) {
        return [];
    }
    if (n === 1) {
        return [nums[0]];
    }

    // Step 1: Precompute the maximum element to the left of each index (inclusive of the element itself for the check, but we need strictly less)
    // maxLeft[i] will store the maximum of nums[0...i-1]
    const maxLeft = new Array(n);
    maxLeft[0] = -Infinity;
    for (let i = 1; i < n; i++) {
        maxLeft[i] = Math.max(maxLeft[i - 1], nums[i - 1]);
    }

    // Step 2: Precompute the maximum element to the right of each index (inclusive of the element itself for the check, but we need strictly less)
    // maxRight[i] will store the maximum of nums[i+1...n-1]
    const maxRight = new Array(n);
    maxRight[n - 1] = -Infinity;
    for (let i = n - 2; i >= 0; i--) {
        maxRight[i] = Math.max(maxRight[i + 1], nums[i + 1]);
    }

    // Step 3: Identify valid elements
    const validElements = [];
    for (let i = 0; i < n; i++) {
        // Condition 1: Strictly greater than all elements to the left
        // For i=0, maxLeft[0] is -Infinity, so nums[0] > -Infinity is true.
        const greaterThanLeft = nums[i] > maxLeft[i];

        // Condition 2: Strictly greater than all elements to the right
        // For i=n-1, maxRight[n-1] is -Infinity, so nums[n-1] > -Infinity is true.
        const greaterThanRight = nums[i] > maxRight[i];

        // An element is valid if it meets at least one condition.
        // Note: The problem states: "If nums[i] satisfies AT LEAST ONE condition..."
