        // nums = [1, 2, 4, 2, 3, 2]
        // i=0 (1): Left (-inf) OK. Right (4) FAIL. Valid (by 1). -> Output: [1, ...]
        // i=1 (2): Left (1) OK. Right (4) FAIL. Valid (by 1). -> Output: [1, 2, ...]
        // i=2 (4): Left (2) OK. Right (3) OK. Valid (by 1 & 2). -> Output: [1, 2, 4, ...]
        // i=3 (2): Left (4) FAIL. Right (3) FAIL. Valid (by 1 or 2)? NO.
        // i=4 (3): Left (4) FAIL. Right (2) OK. Valid (by 2). -> Output: [1, 2, 4, 3, ...]
        // i=5 (2): Left (3) FAIL. Right (-inf) OK. Valid (by 2). -> Output: [1, 2, 4, 3, 2]
        //
        // The example output [1, 2, 4, 3, 2] suggests that for i=3 (value 2), it was NOT included.
        // For i=3 (value 2):
        // Left max is max(1, 2, 4) = 4. 2 > 4 is FALSE.
        // Right max is max(3, 2) = 3. 2 > 3 is FALSE.
        // Since both are false, it is excluded, which matches "AT LEAST ONE".
        //
        // It appears the condition for validity is actually:
        // (nums[i] > maxLeft[i]) OR (nums[i] > maxRight[i])

        if (greaterThanLeft || greaterThanRight) {
            validElements.push(nums[i]);
        }
    }

    return validElements;
}

